var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"이런 좁은 장소에서… 훈련된 전투부대와 호각으로 싸운다고?","JPN":"こんな限られたスペースしかない場所で……熟練の戦闘部隊と互角で戦うだと？","ENG":"How is she able to fight on par with a professionally trained combat unit in such a narrow place...?","TWN":"在這麼狹窄的空間…竟然可以和訓練有素的戰鬥部隊抗衡？"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"더 이상의 살생과 저항은 무의미하다고 판단되오.","JPN":"これ以上の犠牲と、抵抗は無駄だと思われます。","ENG":"Further killing and resistance is futile.","TWN":"不要再繼續無謂的殺生和抵抗。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이제 그만 포기하는 걸 권하리다.","JPN":"もう諦めてはどうでしょう。","ENG":"I suggest you surrender.","TWN":"勸你們棄械投降。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"흥, 협상을 원한다는 건 결국 네놈도 지쳐간다는 뜻이지.","JPN":"ふん、そうやって歩み寄ってきたということは、どうせ貴様だって体力が尽きてきているんだろう。","ENG":"Hmph. Negotiation only means that you are getting tired.","TWN":"哼，想要休兵就表示你不行了吧？"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"하지만 이쪽은 아직 한참 남았다.","JPN":"だが、こっちにはまだまだ余力がある。","ENG":"Unfortunately for you, we still have more men to count.","TWN":"但我們還有餘力呢。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"그만 두시죠, 지휘관님.","JPN":"そのくらいにしましょう、指揮官。","ENG":"Commander, I think it's time you stopped.","TWN":"指揮官，住手。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"…뭐냐? 비전투인원은 밖에서 기다리라고 했을 텐데.","JPN":"……何だ？　非戦闘員は外で待機するよう、命令したはずだが。","ENG":"...What? I thought I told all non-combatants to wait outside.","TWN":"…搞什麼？我不是說非作戰人員一律在外等候嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"상관의 명령이 말 같지 않나? 부사관?","JPN":"上官の命令に逆らっていいとでも？　下士官？","ENG":"You dare defy my orders, Sergeant?","TWN":"你把長官的話當耳邊風嗎，副官？"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"저 여자 말이 맞습니다. 요령도 없이 머릿수로 밀어붙이는 짓은 그만두자고요.","JPN":"あの女の言うとおりです。人員数にかまけて無駄に攻め続けるのはやめましょう。","ENG":"The girl is right. We should stop these mindless attacks based on numbers.","TWN":"她說的沒錯，沒本事只能靠人數優勢，這樣吃相太難看。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"병사들이 아깝잖아요? 아무리 파리 같은 목숨이라도.","JPN":"いくら虫同然の価値しかないとはいえ、兵士の命がもったいなくはありませんか？","ENG":"It is a waste of manpower, don't you think? Even if their lives are worthless.","TWN":"士兵只是無謂地犧牲不是嗎？雖然他們死不足惜。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"입단한 지 얼마 되지도 않은 풋내기가 부사령관님께서 좀 예뻐해 주셨다고 건방을 떠는군.","JPN":"入団して間もない貴様が、副司令官に少し気に入られたからと調子に乗りやがって。","ENG":"Getting cocky that you're on the deputy commander's good side, eh?","TWN":"你一個才剛加入沒多久的新人，因為副司令官喜歡你，就這麼目中無人嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"애초에 네 역할은 엘릭서를 만들고 파는 것뿐이다.","JPN":"そもそも貴様の役割はエリクサーを作り、売ることだろう。","ENG":"Your role in all of this is to only make and sell the Elixir, boy.","TWN":"你的功能就只是製作販賣聖水而已。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"내가 주관하는 작전에 주제넘게 참견 말도록.","JPN":"私が指揮を執る作戦に、口を出すのはやめろ。","ENG":"Stop interfering with my operation. I'm the one in charge here.","TWN":"這場作戰是由我來主導，沒有你插嘴的餘地。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"애초에 제 계획이 아니었으면 저 여자를 여기까지 끌어들이지도 못했을 텐데요.","JPN":"私の計画がなかったら、そもそもあの女をここに連れてくることはできなかったと思いますが。","ENG":"If it weren't for my plans, you wouldn't have been able to lure her here.","TWN":"要不是我想到這個辦法，能把那女的引到這裡來嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"흥…","JPN":"ほう……？","ENG":"Hmph...","TWN":"哼…"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"그렇게 말하는 네놈은 저 괴물을 제압할 다른 좋은 수라도 있나?","JPN":"ならば聞こう。貴様にはあの化け物を制圧する妙策でもあるのか？","ENG":"Then, pray tell, what is your brilliant plan for subduing that monster?","TWN":"你這麼有辦法，那你倒是說說看要怎麼制伏那個怪物？"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"물론이죠.","JPN":"もちろんです。","ENG":"Just a moment.","TWN":"沒問題。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"시간을 조금만 주시면, 제가 잘 설득해보겠습니다.","JPN":"少し時間をいただければ、私から説得してみます。","ENG":"If you give me some time, I'll try to persuade her.","TWN":"給我點時間，我會說服她。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"크헉…!!","JPN":"ぐはっ……！！","ENG":"Kuh...!!","TWN":"唔呃…！！"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"거기서 손끝 하나 움직이면 네 친구는 죽어.","JPN":"指一本でも動かしてみろ、お前の友達が死ぬぞ。","ENG":"Move even the slightest, and your friend here will die.","TWN":"你要是敢再動一根手指，我就殺了他。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"멈춘다고? 저런 협박이 통한단 말인가?","JPN":"止まった……？　あんな脅しが通用するのか？","ENG":"She stopped?! That kind of threat actually works?","TWN":"停了？她吃這招？"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"이런 간단한 방법이 통할 줄은 나도 몰랐어.","JPN":"僕だって、こんな単純な方法が通じるとは思っていなかったよ。","ENG":"I didn't know that something this simple would work on you.","TWN":"我也沒想到這麼簡單的方法竟然有效。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"네가 나이엘 양을 지키려고 총구 앞에 뛰어들기 전까지는 말이야.","JPN":"お前がナイエルを守るため、飛んでくる銃弾に身を投げ出すのを見るまではな。","ENG":"Until you decided to put yourself in harm's way to protect Naielle.","TWN":"你原本是個殺人無數的殺手，"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"사람을 죽이는 살수가 사람을 살리기 위해 자신을 희생하다니….","JPN":"殺人鬼が、人を助けるために自分の命を犠牲にするなんて……","ENG":"An assassin sacrificing herself to save a life...","TWN":"卻願意為了保護奈爾而擋在槍口前犧牲自己…"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"스스로 생각해도 웃기지 않아?","JPN":"おかしな話だと思わないか？","ENG":"Don't you find that funny as well?","TWN":"你自己不覺得很可笑嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"그래서 결정했지. 네 주변 친구들을 이용하기로.","JPN":"だから、僕は思ったんだ。お前のことは周りから攻めていけばいいんだって。","ENG":"That's when I decided to use your friends around you.","TWN":"所以我決定要利用你周圍的朋友。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"흑동의 암살자는 모두의 이름을 기억하되 그 누구의 이름도 부르지 않는다.","JPN":"黒東の暗殺者はすべての名を覚えたとしても、その名を呼ばない。","ENG":"Black East members remember everyone's names, but we do not call anyone by them.","TWN":"黑東的刺客要記住每個人的名字，但不能提及任何人的名字。"},"stage":{"bg":"CLAN","bgm":"THEMA_REPLACER","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"이름이 가진 온기에 냉정이 식는 순간 망설임이 생기고… 망설임을 가진 암살자는 쓸모가 없어질 테니 말이다.","JPN":"名が持つ温かさに冷静さがぬるくなる瞬間、迷いが生じ……迷いのある暗殺者は使い物にならなくなるからな。","ENG":"Names have warmth that creates hesitation... And an assassin with hesitation is useless.","TWN":"因為當你叫對方名字的瞬間，就會打破雙方的隔閡，於是會產生猶豫…猶豫不決的刺客等於是廢人。"},"stage":{"bg":"CLAN","bgm":"THEMA_REPLACER","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…그 말이 맞는 것 같구려.","JPN":"……まったくそのとおりのようですね。","ENG":"...It seems that he was right.","TWN":"…那番話有點道理。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이름을 부르지 않는 것만으로는… 망설임을 피할 수 없었나 보오.","JPN":"名前を呼ばないだけでは……迷いは防げない。","ENG":"However, not addressing others by name... is not enough to avoid hesitation.","TWN":"但光是不喊出名字…似乎無法克服猶豫不決。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"넌 내가 기다리던 가장 이상적인 사람이야.","JPN":"お前は僕が待っていた理想そのものだ。","ENG":"You're the ideal person I've been waiting for.","TWN":"你就是我在等的人。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"네가 내 것이 되는 것만으로, 난 많은 목표를 이룰 수 있어.","JPN":"お前が僕のモノになれば、僕はたくさんの目標を叶えられる。","ENG":"Just by having you, I can achieve many of my objectives.","TWN":"只要你成為我的，我就可以達成許多目標。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"그러니 이제 패배를 인정해.","JPN":"だから、もう負けを認めるんだ。","ENG":"So, admit defeat already.","TWN":"所以你認輸吧。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"날 백서의 문주로 인정하고 반려로서 섬기는 거야.","JPN":"僕を白西の門主として認め、伴侶として受け入れろ。","ENG":"Acknowledge me as the leader of White West and become my wife.","TWN":"承認我是白西的幫主，接受我做你的伴侶。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"그 뒤엔, 내가 널 지금보다 강한 신인류로 거듭나게 해줄 테니.","JPN":"そしたら、僕がお前を今よりも強い新人類として生まれ変わらせてあげるよ。","ENG":"After that, I will guide you to New Humanity, making you stronger than you ever were.","TWN":"然後，我會把你打造成比現在更厲害的新人類。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대가 본인에게 요구한 것은 움직이지 않는 것뿐.","JPN":"貴殿が自分に求めたのは動かないことだけ。","ENG":"All you asked of me was not to move.","TWN":"是你要求在下不要動，"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그것만으로는 패배를 인정할 수 없소.","JPN":"それだけでは負けとは認められません。","ENG":"My lack of movement is not enough to admit defeat.","TWN":"這樣在下無法認輸。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"쓸데없는 고집이네. 굳이 이 이상 피를 볼 필요는 없지 않아?","JPN":"そう意地を張るな。これ以上の犠牲は出したくないだろう？","ENG":"Stop being so stubborn. Do you really have to see more bloodshed?","TWN":"你還真是固執，不需要見血吧？"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"질질 끌 필요 없다, 부사관.","JPN":"時間をあまり使うな、下士官。","ENG":"There's no need to keep dragging this, Sergeant.","TWN":"不要再拖下去，副官。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"10분 안으로 끝내라.","JPN":"10分以内に終わらせろ。","ENG":"Finish it within 10 minutes.","TWN":"10分鐘之內解決！"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"…충분합니다.","JPN":"……十分です。","ENG":"...That is more than enough time.","TWN":"…很夠了。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"들었지? 지금부턴 항복이라고 말하는 정도론 끝나지 않을 거야.","JPN":"聞いただろう？　もう、降参したってすぐにはやめてやらないからな。","ENG":"Did you hear that? Now, your surrender won't be enough to end this.","TWN":"聽到了吧？現在不是一句投降就沒事囉。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"제발 거둬 달라고 울고불고하며 애원하게 해줄 테니까.","JPN":"お願いだからもう止めてくれと、泣き叫びながら懇願させてやるよ。","ENG":"I'll make you beg me to take you in.","TWN":"我會讓你哭著求我住手。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"윽… 시엘…","JPN":"うっ……シエル……","ENG":"Ngh... Ciel...","TWN":"呃… 希爾…"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};